function detectTianYi(pillars, day_stem, year_stem) {
  const targets = [...lookup[day_stem], ...lookup[year_stem]];
  return ['year','month','day','hour'].filter(p => targets.includes(pillars[p]?.branch));
}

function detectWenChang(pillars, day_stem) {
  const target = lookup[day_stem];
  return ['year','month','day','hour'].filter(p => pillars[p]?.branch === target);
}

